// ── Helpers ────────────────────────────────────────────────────
const MONTHS = ["January","February","March","April","May","June",
                "July","August","September","October","November","December"];

function getDoctorName() {
  try { return JSON.parse(localStorage.getItem("user"))?.name || "Doctor"; } catch { return "Doctor"; }
}

// Derive analysis data from raw prescriptions
function analyseRx(prescriptions, year, month) {
  // month is 0-indexed
  const inPeriod = prescriptions.filter(rx => {
    const d = new Date(rx.createdAt);
    return d.getFullYear() === year && d.getMonth() === month;
  });
  const prevMonth = month === 0 ? 11 : month - 1;
  const prevYear  = month === 0 ? year - 1 : year;
  const inPrev    = prescriptions.filter(rx => {
    const d = new Date(rx.createdAt);
    return d.getFullYear() === prevYear && d.getMonth() === prevMonth;
  });

  // Count medicine occurrences
  const countMeds = (list) => {
    const map = {};
    list.forEach(rx => {
      (rx.medications || []).forEach(med => {
        const key = med.name?.trim();
        if (!key) return;
        if (!map[key]) map[key] = { name: key, count: 0 };
        map[key].count++;
      });
    });
    return map;
  };

  const currMap = countMeds(inPeriod);
  const prevMap = countMeds(inPrev);

  // Top medicines array
  const topMeds = Object.values(currMap)
    .map(m => ({ ...m, lastMonth: prevMap[m.name]?.count || 0 }))
    .sort((a, b) => b.count - a.count)
    .slice(0, 15);

  // Category breakdown — infer from drug name keywords
  const catMap = {};
  inPeriod.forEach(rx => {
    (rx.medications || []).forEach(med => {
      const cat = inferCategory(med.name || "");
      if (!catMap[cat]) catMap[cat] = 0;
      catMap[cat]++;
    });
  });
  const categories = Object.entries(catMap)
    .map(([cat, total]) => ({ cat, total }))
    .sort((a, b) => b.total - a.total);

  // 6-month trend (ending at selected month)
  const trend = [];
  for (let i = 5; i >= 0; i--) {
    let m = month - i;
    let y = year;
    while (m < 0) { m += 12; y--; }
    const slice = prescriptions.filter(rx => {
      const d = new Date(rx.createdAt);
      return d.getFullYear() === y && d.getMonth() === m;
    });
    const totalMeds = slice.reduce((s, rx) => s + (rx.medications?.length || 0), 0);
    trend.push({ month: MONTHS[m].slice(0, 3), total: totalMeds, rxCount: slice.length });
  }

  return {
    totalRx:    inPeriod.length,
    totalMeds:  inPeriod.reduce((s, rx) => s + (rx.medications?.length || 0), 0),
    uniqueMeds: Object.keys(currMap).length,
    topMeds,
    categories,
    trend,
  };
}

const CAT_KEYWORDS = {
  "Antidiabetic":     ["metformin","glipizide","insulin","sitagliptin","gliclazide","glibenclamide","empagliflozin","dapagliflozin"],
  "Antihypertensive": ["lisinopril","amlodipine","losartan","atenolol","ramipril","telmisartan","valsartan","nifedipine","candesartan","bisoprolol"],
  "Antibiotic":       ["amoxicillin","augmentin","azithromycin","cephalexin","ciprofloxacin","metronidazole","doxycycline","cloxacillin","co-amoxiclav"],
  "Analgesic":        ["paracetamol","ibuprofen","diclofenac","tramadol","codeine","mefenamic","aspirin"],
  "Antacid/GI":       ["omeprazole","pantoprazole","ranitidine","esomeprazole","domperidone","ondansetron","metoclopramide"],
  "Statin":           ["atorvastatin","simvastatin","rosuvastatin","pravastatin"],
  "Vitamin/Supplement":["vitamin","zinc","iron","calcium","ferrous","folic","b12","vit d"],
  "Antihistamine":    ["cetirizine","loratadine","chlorpheniramine","fexofenadine","promethazine"],
  "Antiviral":        ["acyclovir","oseltamivir","valacyclovir","famciclovir"],
  "Thyroid":          ["thyroxine","levothyroxine","methimazole","carbimazole","propylthiouracil"],
  "Respiratory":      ["salbutamol","prednisolone","beclomethasone","montelukast","fluticasone","ipratropium"],
};
const CAT_COLORS = {
  "Antidiabetic":"#1565C0","Antihypertensive":"#00897B","Antibiotic":"#E65100",
  "Analgesic":"#EC4899","Antacid/GI":"#F59E0B","Statin":"#7B1FA2",
  "Vitamin/Supplement":"#84CC16","Antihistamine":"#06B6D4","Antiviral":"#EF4444",
  "Thyroid":"#F97316","Respiratory":"#8B5CF6","Other":"#94A3B8",
};
function inferCategory(name) {
  const lower = name.toLowerCase();
  for (const [cat, keywords] of Object.entries(CAT_KEYWORDS)) {
    if (keywords.some(k => lower.includes(k))) return cat;
  }
  return "Other";
}

// ── Embedded logo (base64) for PDF ────────────────────────────
const LOGO_B64 = "data:image/png;base64,";

// ── PDF Report Generator (client-side jsPDF) ──────────────────
async function generatePDF(data, doctorName, year, month, allRx) {
  const doc = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
  const W = 210, marginL = 18, marginR = 18, contentW = W - marginL - marginR;
  const primaryBlue = [13, 33, 55];
  const accentBlue  = [21, 101, 192];
  const accentTeal  = [0, 172, 193];
  const lightGray   = [248, 250, 252];
  const borderGray  = [226, 232, 240];
  const monthLabel  = MONTHS[month];

  // ── Page 1: Cover + KPIs + Top Medicines ─────────────────────
  // Header band
  doc.setFillColor(...primaryBlue);
  doc.rect(0, 0, W, 42, "F");

  // Accent stripe
  doc.setFillColor(...accentTeal);
  doc.rect(0, 38, W, 4, "F");

  // Logo image
  doc.addImage(LOGO_B64, "PNG", marginL, 8, 22, 22);

  // Title
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(18);
  doc.setFont("helvetica", "bold");
  doc.text("Medicine Prescription Analysis", marginL + 26, 16);
  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  doc.text(`People's Health Care · ${monthLabel} ${year}`, marginL + 26, 23);
  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  doc.text("No 123 Matara - Akuressa Hwy, Matara", marginL + 26, 29);
  doc.setFontSize(8.5);
  doc.text(`Prepared by: Dr. ${doctorName}`, marginL + 26, 35);

  // Generated date — top right
  doc.setFontSize(7.5);
  doc.setTextColor(180, 210, 240);
  doc.text(`Generated: ${new Date().toLocaleDateString("en-GB", { day:"2-digit", month:"short", year:"numeric" })}`, W - marginR, 30, { align: "right" });

  // ── KPI Cards row ────────────────────────────────────────────
  let y = 52;
  const kpis = [
    { label: "Total Prescriptions", value: String(data.totalRx),    sub: monthLabel,       color: accentBlue },
    { label: "Medications Issued",  value: String(data.totalMeds),   sub: "items",          color: [0,137,123] },
    { label: "Unique Medicines",    value: String(data.uniqueMeds),  sub: "distinct drugs", color: [230,81,0] },
    { label: "Top Category",        value: data.categories[0]?.cat || "—", sub: `${data.categories[0]?.total || 0} prescribed`, color: [123,31,162] },
  ];
  const kW = contentW / 4 - 3;
  kpis.forEach((k, i) => {
    const x = marginL + i * (kW + 4);
    doc.setFillColor(...lightGray);
    doc.roundedRect(x, y, kW, 22, 3, 3, "F");
    doc.setFillColor(...k.color);
    doc.roundedRect(x, y, 3, 22, 1.5, 1.5, "F");
    doc.setTextColor(...k.color);
    doc.setFontSize(14);
    doc.setFont("helvetica", "bold");
    doc.text(k.value.length > 12 ? k.value.slice(0,12) : k.value, x + 7, y + 10);
    doc.setTextColor(50, 50, 50);
    doc.setFontSize(7.5);
    doc.setFont("helvetica", "bold");
    doc.text(k.label, x + 7, y + 16);
    doc.setFont("helvetica", "normal");
    doc.setTextColor(130, 130, 130);
    doc.text(k.sub, x + 7, y + 20);
  });

  // ── Top Medicines table ──────────────────────────────────────
  y += 30;
  doc.setFontSize(11);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(...primaryBlue);
  doc.text("Most Prescribed Medicines", marginL, y);
  doc.setDrawColor(...accentTeal);
  doc.setLineWidth(0.5);
  doc.line(marginL, y + 2, marginL + 70, y + 2);
  y += 6;

  const tableRows = data.topMeds.slice(0, 12).map((med, idx) => {
    const delta = med.count - med.lastMonth;
    const trend = delta > 0 ? `↑ +${delta}` : delta < 0 ? `↓ ${delta}` : "→ 0";
    return [
      `#${idx + 1}`,
      med.name,
      inferCategory(med.name),
      String(med.count),
      String(med.lastMonth),
      trend,
    ];
  });

  autoTable(doc, {
    startY: y,
    head: [["Rank", "Medicine Name", "Category", "This Month", "Prev Month", "Trend"]],
    body: tableRows,
    margin: { left: marginL, right: marginR },
    styles: { fontSize: 8.5, cellPadding: 3, lineColor: borderGray, lineWidth: 0.2 },
    headStyles: {
      fillColor: primaryBlue,
      textColor: [255,255,255],
      fontStyle: "bold",
      fontSize: 8.5,
    },
    alternateRowStyles: { fillColor: lightGray },
    columnStyles: {
      0: { cellWidth: 12, halign: "center", fontStyle: "bold" },
      1: { cellWidth: 62 },
      2: { cellWidth: 36 },
      3: { cellWidth: 22, halign: "center", fontStyle: "bold" },
      4: { cellWidth: 22, halign: "center" },
      5: { cellWidth: 20, halign: "center" },
    },
    didParseCell: (d) => {
      if (d.section === "body" && d.column.index === 5) {
        const v = d.cell.raw || "";
        if (v.startsWith("↑")) d.cell.styles.textColor = [0,137,123];
        else if (v.startsWith("↓")) d.cell.styles.textColor = [220,38,38];
        else d.cell.styles.textColor = [100,100,100];
      }
      if (d.section === "body" && d.column.index === 0) {
        if (d.row.index === 0) d.cell.styles.textColor = [183,130,0];
        else if (d.row.index === 1) d.cell.styles.textColor = [100,100,100];
        else if (d.row.index === 2) d.cell.styles.textColor = [180,100,0];
      }
    },
  });

  // ── Page 2: Category breakdown + 6-month trend + insights ────
  doc.addPage();

  // Page 2 sub-header
  doc.setFillColor(...primaryBlue);
  doc.rect(0, 0, W, 16, "F");
  doc.setFillColor(...accentTeal);
  doc.rect(0, 14, W, 2, "F");
  doc.addImage(LOGO_B64, "PNG", marginL, 1, 12, 12);
  doc.setTextColor(255,255,255);
  doc.setFontSize(10);
  doc.setFont("helvetica", "bold");
  doc.text(`Medicine Analysis — ${monthLabel} ${year} (continued)`, marginL + 18, 10);

  y = 24;

  // Category breakdown horizontal bars
  doc.setFontSize(11);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(...primaryBlue);
  doc.text("Prescriptions by Category", marginL, y);
  doc.setDrawColor(...accentTeal);
  doc.setLineWidth(0.5);
  doc.line(marginL, y + 2, marginL + 80, y + 2);
  y += 8;

  const maxCat = Math.max(...data.categories.map(c => c.total), 1);
  const barAreaW = contentW * 0.55;
  data.categories.slice(0, 8).forEach((c, i) => {
    const barY = y + i * 9;
    const catColor = CAT_COLORS[c.cat] || "#94A3B8";
    const rgb = hexToRgb(catColor);
    const fillW = Math.max((c.total / maxCat) * barAreaW, 2);

    // Label
    doc.setFontSize(8);
    doc.setFont("helvetica", "normal");
    doc.setTextColor(50,50,50);
    doc.text(c.cat, marginL, barY + 4.5);

    // Bar bg
    doc.setFillColor(...borderGray);
    doc.roundedRect(marginL + 46, barY, barAreaW, 6, 2, 2, "F");

    // Bar fill
    doc.setFillColor(...rgb);
    doc.roundedRect(marginL + 46, barY, fillW, 6, 2, 2, "F");

    // Count
    doc.setFontSize(8);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(...rgb);
    doc.text(String(c.total), marginL + 46 + barAreaW + 4, barY + 4.5);
  });

  y += data.categories.slice(0, 8).length * 9 + 10;

  // 6-month trend bar chart
  doc.setFontSize(11);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(...primaryBlue);
  doc.text("6-Month Prescription Volume Trend", marginL, y);
  doc.setDrawColor(...accentTeal);
  doc.setLineWidth(0.5);
  doc.line(marginL, y + 2, marginL + 100, y + 2);
  y += 8;

  const chartH = 40;
  const chartW = contentW;
  const maxTrend = Math.max(...data.trend.map(t => t.total), 1);
  const barW = chartW / data.trend.length - 4;

  // Chart bg
  doc.setFillColor(...lightGray);
  doc.roundedRect(marginL, y, chartW, chartH + 12, 3, 3, "F");

  data.trend.forEach((t, i) => {
    const bx = marginL + i * (barW + 4) + 2;
    const barH = Math.max((t.total / maxTrend) * chartH, 2);
    const by   = y + chartH - barH;
    const isLast = i === data.trend.length - 1;

    doc.setFillColor(...(isLast ? accentBlue : [170,200,240]));
    doc.roundedRect(bx, by, barW, barH, 1.5, 1.5, "F");

    // Value
    doc.setFontSize(7);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(...(isLast ? accentBlue : [100,130,180]));
    doc.text(String(t.total), bx + barW / 2, by - 1.5, { align: "center" });

    // Month label
    doc.setFontSize(7);
    doc.setFont("helvetica", "normal");
    doc.setTextColor(80, 80, 80);
    doc.text(t.month, bx + barW / 2, y + chartH + 8, { align: "center" });
  });

  y += chartH + 22;

  // Insights / summary
  doc.setFontSize(11);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(...primaryBlue);
  doc.text("Summary & Insights", marginL, y);
  doc.setDrawColor(...accentTeal);
  doc.setLineWidth(0.5);
  doc.line(marginL, y + 2, marginL + 65, y + 2);
  y += 8;

  const insights = buildInsights(data);
  insights.forEach((ins, i) => {
    const rgb = hexToRgb(ins.color);
    doc.setFillColor(...lightGray);
    doc.roundedRect(marginL, y, contentW, 16, 3, 3, "F");
    doc.setFillColor(...rgb);
    doc.roundedRect(marginL, y, 3, 16, 1.5, 1.5, "F");
    doc.setFontSize(8.5);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(...rgb);
    doc.text(ins.title, marginL + 7, y + 6);
    doc.setFont("helvetica", "normal");
    doc.setTextColor(70, 70, 70);
    const lines = doc.splitTextToSize(ins.desc, contentW - 10);
    doc.text(lines[0], marginL + 7, y + 11.5);
    y += 20;
  });

  // ── Page 3: Full prescription log ────────────────────────────
  doc.addPage();
  doc.setFillColor(...primaryBlue);
  doc.rect(0, 0, W, 16, "F");
  doc.setFillColor(...accentTeal);
  doc.rect(0, 14, W, 2, "F");
  doc.addImage(LOGO_B64, "PNG", marginL, 1, 12, 12);
  doc.setTextColor(255,255,255);
  doc.setFontSize(10);
  doc.setFont("helvetica", "bold");
  doc.text(`Prescription Log — ${monthLabel} ${year}`, marginL + 18, 10);

  const logRx = allRx.filter(rx => {
    const d = new Date(rx.createdAt);
    return d.getFullYear() === year && d.getMonth() === month;
  });

  const logRows = logRx.flatMap(rx =>
    (rx.medications || []).map((med, i) => [
      i === 0 ? rx.prescriptionId : "",
      i === 0 ? rx.patientName : "",
      i === 0 ? new Date(rx.createdAt).toLocaleDateString("en-GB", {day:"2-digit",month:"short"}) : "",
      med.name,
      med.dosage || "—",
      med.duration || "—",
    ])
  );

  autoTable(doc, {
    startY: 22,
    head: [["Rx ID", "Patient", "Date", "Medicine", "Dosage", "Duration"]],
    body: logRows.length ? logRows : [["—","No prescriptions","—","—","—","—"]],
    margin: { left: marginL, right: marginR },
    styles: { fontSize: 7.5, cellPadding: 2.5, lineColor: borderGray, lineWidth: 0.2 },
    headStyles: { fillColor: primaryBlue, textColor: [255,255,255], fontStyle: "bold", fontSize: 8 },
    alternateRowStyles: { fillColor: lightGray },
    columnStyles: {
      0: { cellWidth: 28, fontStyle: "bold", textColor: accentBlue },
      1: { cellWidth: 36 },
      2: { cellWidth: 18 },
      3: { cellWidth: 52 },
      4: { cellWidth: 30 },
      5: { cellWidth: 20 },
    },
  });

  // ── Footer on all pages ──────────────────────────────────────
  const pageCount = doc.internal.getNumberOfPages();
  for (let pg = 1; pg <= pageCount; pg++) {
    doc.setPage(pg);
    doc.setFillColor(245, 247, 250);
    doc.rect(0, 285, W, 12, "F");
    doc.setFontSize(7);
    doc.setFont("helvetica", "normal");
    doc.setTextColor(150,150,150);
    doc.text("People's Health Care · Confidential Medical Report · For internal use only", marginL, 292);
    doc.text(`Page ${pg} of ${pageCount}`, W - marginR, 292, { align: "right" });
  }

  doc.save(`Medicine_Analysis_${monthLabel}_${year}.pdf`);
}

// ── helpers ───────────────────────────────────────────────────
function hexToRgb(hex) {
  const r = parseInt(hex.slice(1,3),16);
  const g = parseInt(hex.slice(3,5),16);
  const b = parseInt(hex.slice(5,7),16);
  return [r,g,b];
}

function buildInsights(data) {
  const insights = [];
  if (data.topMeds.length > 0) {
    const top = data.topMeds[0];
    const delta = top.count - top.lastMonth;
    insights.push({
      title: `#1 Medicine: ${top.name}`,
      desc: delta > 0
        ? `Prescribed ${top.count} times this period — up ${delta} from last month (+${Math.round(delta/Math.max(top.lastMonth,1)*100)}%).`
        : delta < 0
          ? `Prescribed ${top.count} times this period — down ${Math.abs(delta)} from last month.`
          : `Prescribed ${top.count} times, unchanged from last month.`,
      color: "#1565C0",
    });
  }
  if (data.categories.length > 0) {
    insights.push({
      title: `Leading Category: ${data.categories[0].cat}`,
      desc: `${data.categories[0].cat} medicines account for ${data.categories[0].total} prescriptions — the highest of any category this period.`,
      color: CAT_COLORS[data.categories[0].cat] || "#7B1FA2",
    });
  }
  const trendLast  = data.trend[5]?.total || 0;
  const trendPrev  = data.trend[4]?.total || 0;
  if (trendPrev > 0) {
    const pct = Math.round(((trendLast - trendPrev) / trendPrev) * 100);
    insights.push({
      title: `Month-on-Month Volume: ${pct >= 0 ? "+" : ""}${pct}%`,
      desc: `Total medication items moved from ${trendPrev} last month to ${trendLast} this month across ${data.totalRx} prescriptions.`,
      color: pct >= 0 ? "#00897B" : "#E65100",
    });
  }
  return insights;
}

// ══════════════════════════════════════════════════════════════
// Main Component
// ══════════════════════════════════════════════════════════════
export default function DoctorMedicineAnalysis() {
  const now        = new Date();
  const doctorName = getDoctorName();

  const [allRx,       setAllRx]       = useState([]);
  const [loading,     setLoading]     = useState(true);
  const [selYear,     setSelYear]     = useState(now.getFullYear());
  const [selMonth,    setSelMonth]    = useState(now.getMonth());
  const [medSearch,   setMedSearch]   = useState("");
  const [medFilter,   setMedFilter]   = useState("All");
  const [sortBy,      setSortBy]      = useState("prescribed");
  const [trendView,   setTrendView]   = useState("total");
  const [generating,  setGenerating]  = useState(false);

  // Available years (current year ± 3)
  const years = Array.from({ length: 4 }, (_, i) => now.getFullYear() - 3 + i + 1);

  const loadRx = async (silent = false) => {
    if (!silent) setLoading(true);
    try {
      const res = await api.get("/prescriptions?limit=2000");
      setAllRx(res.data.prescriptions || []);
    } catch { setAllRx([]); }
    finally { if (!silent) setLoading(false); }
  };

  useEffect(() => { loadRx(); }, []);

  // ── Auto-refresh every 5 seconds (silent — no flicker) ───────
  useEffect(() => {
    const interval = setInterval(() => loadRx(true), 5_000);
    return () => clearInterval(interval);
  }, []);

  const data = useMemo(() => analyseRx(allRx, selYear, selMonth), [allRx, selYear, selMonth]);

  // Unique categories from top meds for filter pills
  const allCats = useMemo(() => ["All", ...new Set(data.topMeds.map(m => inferCategory(m.name)))], [data.topMeds]);

  const filteredMeds = useMemo(() => {
    let list = data.topMeds.filter(m => {
      const q = medSearch.toLowerCase();
      const matchQ   = !q || m.name.toLowerCase().includes(q);
      const matchCat = medFilter === "All" || inferCategory(m.name) === medFilter;
      return matchQ && matchCat;
    });
    if (sortBy === "growth") list = [...list].sort((a, b) => (b.count - b.lastMonth) - (a.count - a.lastMonth));
    return list;
  }, [data.topMeds, medSearch, medFilter, sortBy]);

  const maxMed   = Math.max(...data.topMeds.map(m => m.count), 1);
  const maxCatV  = Math.max(...data.categories.map(c => c.total), 1);
  const maxTrend = Math.max(...data.trend.map(t => t.total), 1);

  const insights = buildInsights(data);

  const handleDownload = async () => {
    setGenerating(true);
    try {
      await generatePDF(data, doctorName, selYear, selMonth, allRx);
    } finally {
      setGenerating(false);
    }
  };

  // Trend month-on-month change
  const trendDelta  = data.trend[5]?.total - data.trend[4]?.total || 0;
  const trendPct    = data.trend[4]?.total
    ? Math.round((trendDelta / data.trend[4].total) * 100)
    : 0;

  return (
      <div className="p-6 space-y-6">

        {/* Header */}
        <div className="flex items-start justify-between flex-wrap gap-3">
          <div>
            <h1 className="text-xl font-bold text-gray-800" style={{ fontFamily: "'Playfair Display', serif" }}>
              Medicine Analysis
            </h1>
            <p className="text-sm text-gray-400 mt-1">
              Most prescribed medicines · {MONTHS[selMonth]} {selYear} · Dr. {doctorName}
            </p>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            {/* Month selector */}
            <div className="flex items-center gap-2 bg-white border border-gray-200 rounded-xl px-3 py-2 shadow-sm">
              <svg viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4 text-gray-400">
                <path fillRule="evenodd" d="M6 2a1 1 0 00-1 1v1H4a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V6a2 2 0 00-2-2h-1V3a1 1 0 10-2 0v1H7V3a1 1 0 00-1-1zm0 5a1 1 0 000 2h8a1 1 0 100-2H6z" clipRule="evenodd"/>
              </svg>
              <select
                value={selMonth}
                onChange={e => setSelMonth(Number(e.target.value))}
                className="text-sm text-gray-700 bg-transparent border-none outline-none cursor-pointer font-medium"
              >
                {MONTHS.map((m, i) => <option key={m} value={i}>{m}</option>)}
              </select>
              <select
                value={selYear}
                onChange={e => setSelYear(Number(e.target.value))}
                className="text-sm text-gray-700 bg-transparent border-none outline-none cursor-pointer font-medium"
              >
                {years.map(y => <option key={y} value={y}>{y}</option>)}
              </select>
            </div>

            {/* Download report button */}
            <button
              onClick={handleDownload}
              disabled={generating || loading}
              className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-white text-sm font-semibold shadow-lg transition disabled:opacity-60 hover:scale-105"
              style={{ background: "linear-gradient(135deg, #0D2137, #1565C0)" }}
            >
              {generating ? (
                <div className="w-4 h-4 border-2 border-white/40 border-t-white rounded-full animate-spin"/>
              ) : (
                <DownloadIcon />
              )}
              {generating ? "Generating…" : "Download Report"}
            </button>
          </div>
        </div>

        {/* Loading skeleton */}
        {loading ? (
          <div className="flex items-center justify-center h-64">
            <div className="w-8 h-8 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin"/>
          </div>
        ) : (
          <>
            {/* KPI strip */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
              {[
                { label: "Unique Medicines",    value: data.uniqueMeds, sub: "distinct drugs",         icon: <PillIcon />,   color: "#1565C0", bg: "#E3F2FD", trend: `${data.uniqueMeds}`,   trendUp: true },
                { label: "Total Prescriptions", value: data.totalRx,    sub: MONTHS[selMonth],         icon: <ScriptIcon />, color: "#00897B", bg: "#E0F2F1", trend: `+${data.totalRx}`,     trendUp: true },
                { label: "#1 Most Prescribed",  value: data.topMeds[0]?.name?.split(" ")[0] || "—", sub: `${data.topMeds[0]?.count || 0} times`, icon: <TrophyIcon />, color: "#E65100", bg: "#FFF3E0", trend: data.topMeds[0]?.count > data.topMeds[0]?.lastMonth ? "↑ Up" : "↓ Down", trendUp: data.topMeds[0]?.count >= data.topMeds[0]?.lastMonth },
                { label: "Top Category",        value: data.categories[0]?.cat || "—", sub: `${data.categories[0]?.total || 0} items`, icon: <ChartIcon />, color: "#7B1FA2", bg: "#F3E5F5", trend: data.categories[0]?.total || 0, trendUp: true },
              ].map(card => (
                <div key={card.label} className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm hover:shadow-md transition">
                  <div className="flex items-start justify-between mb-3">
                    <div className="p-2.5 rounded-xl" style={{ background: card.bg, color: card.color }}>
                      {card.icon}
                    </div>
                    <span className={`text-xs font-semibold px-2 py-1 rounded-full ${
                      card.trendUp ? "bg-green-50 text-green-600" : "bg-red-50 text-red-500"
                    }`}>
                      {card.trend}
                    </span>
                  </div>
                  <div className="font-bold" style={{ fontFamily: "'Playfair Display', serif", fontSize: "1.8rem", color: "#0D2137" }}>
                    {card.value || "—"}
                  </div>
                  <div className="text-gray-500 text-sm mt-0.5">{card.label}</div>
                  <div className="text-xs text-gray-400 mt-1">{card.sub}</div>
                </div>
              ))}
            </div>

            {/* Empty state */}
            {data.totalRx === 0 && (
              <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-14 text-center">
                <div className="w-14 h-14 rounded-2xl bg-blue-50 flex items-center justify-center mx-auto mb-4" style={{ color: "#1565C0" }}>
                  <PillIcon />
                </div>
                <div className="text-gray-500 font-medium">No prescriptions found for {MONTHS[selMonth]} {selYear}</div>
                <div className="text-gray-400 text-sm mt-1">Try selecting a different month or year.</div>
              </div>
            )}

            {data.totalRx > 0 && (
              <>
                {/* Charts row */}
                <div className="grid lg:grid-cols-2 gap-6">

                  {/* Prescription trend */}
                  <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
                    <div className="flex items-center justify-between mb-4">
                      <div>
                        <h3 className="font-semibold text-gray-800">Prescription Volume Trend</h3>
                        <p className="text-xs text-gray-400 mt-0.5">Medication items — last 6 months</p>
                      </div>
                      <div className="flex gap-1 bg-gray-100 rounded-xl p-1">
                        {[
                          { key: "total",  label: "Items",  color: "#1565C0" },
                          { key: "rxCount", label: "Rx",    color: "#00897B" },
                        ].map(opt => (
                          <button key={opt.key} onClick={() => setTrendView(opt.key)}
                            className={`px-2.5 py-1 rounded-lg text-xs font-semibold transition ${
                              trendView === opt.key ? "bg-white text-gray-800 shadow-sm" : "text-gray-500"
                            }`}>
                            {opt.label}
                          </button>
                        ))}
                      </div>
                    </div>

                    <div className="flex items-end gap-3 h-36 mt-2">
                      {data.trend.map((m, i) => {
                        const val     = m[trendView] ?? m.total;
                        const pct     = Math.round((val / maxTrend) * 100);
                        const isLast  = i === data.trend.length - 1;
                        const barColor = isLast ? "#1565C0" : "#93B8E5";
                        return (
                          <div key={m.month} className="flex-1 flex flex-col items-center gap-1 group">
                            <span className={`text-xs font-bold ${isLast ? "text-gray-800" : "text-gray-400"}`}>{val}</span>
                            <div className="w-full rounded-t-lg transition-all relative"
                              style={{ height: `${Math.max(pct * 0.9, 4)}px`, background: barColor }}>
                              <div className="absolute -top-8 left-1/2 -translate-x-1/2 bg-gray-800 text-white text-xs px-2 py-1 rounded-lg opacity-0 group-hover:opacity-100 transition whitespace-nowrap pointer-events-none z-10">
                                {m.month}: {val}
                              </div>
                            </div>
                            <span className="text-xs text-gray-400">{m.month}</span>
                          </div>
                        );
                      })}
                    </div>

                    <div className="mt-4 flex items-center gap-2 p-3 rounded-xl border border-gray-100 bg-gray-50 text-xs text-gray-500">
                      <span className={`font-semibold ${trendPct >= 0 ? "text-green-600" : "text-red-500"}`}>
                        {trendPct >= 0 ? "↑" : "↓"} {Math.abs(trendPct)}%
                      </span>
                      {trendPct >= 0 ? "increase" : "decrease"} in prescription items vs previous month.
                    </div>
                  </div>

                  {/* Category breakdown */}
                  <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
                    <div className="mb-4">
                      <h3 className="font-semibold text-gray-800">Prescriptions by Category</h3>
                      <p className="text-xs text-gray-400 mt-0.5">Total items per drug class</p>
                    </div>
                    <div className="space-y-3 max-h-52 overflow-y-auto pr-1">
                      {data.categories.length > 0 ? data.categories.map(c => {
                        const color = CAT_COLORS[c.cat] || "#94A3B8";
                        return (
                          <div key={c.cat}>
                            <div className="flex items-center justify-between mb-1">
                              <div className="flex items-center gap-2">
                                <div className="w-2.5 h-2.5 rounded-full flex-shrink-0" style={{ background: color }}/>
                                <span className="text-sm text-gray-700">{c.cat}</span>
                              </div>
                              <span className="text-sm font-bold text-gray-800">{c.total}</span>
                            </div>
                            <div className="h-2.5 bg-gray-100 rounded-full overflow-hidden">
                              <div className="h-2.5 rounded-full transition-all"
                                style={{ width: `${Math.round((c.total / maxCatV) * 100)}%`, background: color }}/>
                            </div>
                          </div>
                        );
                      }) : (
                        <p className="text-sm text-gray-400 text-center py-8">No category data</p>
                      )}
                    </div>
                  </div>
                </div>

                {/* Filter bar */}
                <div className="bg-white rounded-2xl p-4 border border-gray-100 shadow-sm flex flex-wrap items-center gap-3">
                  <div className="flex-1 min-w-48 relative">
                    <svg viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                      <path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd"/>
                    </svg>
                    <input type="text" placeholder="Search medicine name…"
                      value={medSearch} onChange={e => setMedSearch(e.target.value)}
                      className="w-full pl-9 pr-4 py-2 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400 transition"/>
                  </div>
                  <div className="flex gap-2 flex-wrap">
                    {allCats.map(c => (
                      <button key={c} onClick={() => setMedFilter(c)}
                        className={`px-3 py-2 rounded-xl text-xs font-semibold transition ${
                          medFilter === c ? "text-white shadow-md" : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                        }`}
                        style={medFilter === c ? { background: "linear-gradient(135deg, #0D2137, #1565C0)" } : {}}>
                        {c}
                      </button>
                    ))}
                  </div>
                  <div className="flex items-center gap-2 ml-auto">
                    <span className="text-xs text-gray-400">Sort:</span>
                    {[["prescribed","By Volume"],["growth","By Growth"]].map(([v, l]) => (
                      <button key={v} onClick={() => setSortBy(v)}
                        className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition ${
                          sortBy === v ? "bg-blue-100 text-blue-700" : "bg-gray-100 text-gray-500"
                        }`}>{l}</button>
                    ))}
                  </div>
                </div>

                {/* Medicine ranking table */}
                <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
                  <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
                    <div>
                      <h3 className="font-semibold text-gray-800">Most Prescribed Medicines</h3>
                      <p className="text-xs text-gray-400 mt-0.5">Ranked by frequency — {filteredMeds.length} medicines</p>
                    </div>
                  </div>
                  <div className="divide-y divide-gray-50">
                    {filteredMeds.map((med, idx) => {
                      const barPct = Math.round((med.count / maxMed) * 100);
                      const delta  = med.count - med.lastMonth;
                      const trend  = delta > 0
                        ? { icon: "↑", label: `+${delta}`, bg: "bg-green-100", text: "text-green-700" }
                        : delta < 0
                          ? { icon: "↓", label: `${delta}`, bg: "bg-red-100",   text: "text-red-600" }
                          : { icon: "→", label: "0",         bg: "bg-gray-100",  text: "text-gray-500" };
                      const rankText = idx === 0 ? "🥇" : idx === 1 ? "🥈" : idx === 2 ? "🥉" : `#${idx+1}`;
                      const rankCls  = idx === 0
                        ? "bg-gradient-to-br from-yellow-400 to-red-400 text-white"
                        : idx === 1 ? "bg-gray-200 text-gray-700"
                        : idx === 2 ? "bg-amber-100 text-amber-700"
                        : "bg-gray-50 text-gray-400 text-sm";
                      const catColor = CAT_COLORS[inferCategory(med.name)] || "#94A3B8";

                      return (
                        <div key={med.name} className="flex items-center gap-4 px-6 py-4 hover:bg-gray-50 transition">
                          <div className={`w-9 h-9 rounded-xl flex items-center justify-center text-sm font-bold flex-shrink-0 ${rankCls}`}>
                            {rankText}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 flex-wrap mb-1">
                              <span className="text-sm font-semibold text-gray-800">{med.name}</span>
                              <span className="text-xs px-2 py-0.5 rounded-full font-medium"
                                style={{ background: `${catColor}20`, color: catColor }}>
                                {inferCategory(med.name)}
                              </span>
                            </div>
                            <div className="flex items-center gap-2 mt-2">
                              <div className="h-2 bg-gray-100 rounded-full overflow-hidden" style={{ width: "140px" }}>
                                <div className="h-2 rounded-full" style={{ width: `${barPct}%`, background: "linear-gradient(90deg,#1565C0,#00ACC1)" }}/>
                              </div>
                              <span className="text-xs text-gray-400">{barPct}%</span>
                            </div>
                          </div>
                          <div className="flex items-center gap-6 flex-shrink-0">
                            <div className="text-center">
                              <div className="text-2xl font-bold text-gray-800" style={{ fontFamily: "'Playfair Display', serif" }}>
                                {med.count}
                              </div>
                              <div className="text-xs text-gray-400">this month</div>
                            </div>
                            <div className="text-center">
                              <div className="text-sm text-gray-400">{med.lastMonth}</div>
                              <div className="text-xs text-gray-400">last month</div>
                            </div>
                            <div className={`flex items-center gap-1 px-3 py-1.5 rounded-xl text-xs font-bold ${trend.bg} ${trend.text}`}>
                              {trend.icon} {trend.label}
                            </div>
                          </div>
                        </div>
                      );
                    })}
                    {filteredMeds.length === 0 && (
                      <div className="p-12 text-center">
                        <div className="w-10 h-10 rounded-2xl bg-blue-50 flex items-center justify-center mx-auto mb-3" style={{color:"#1565C0"}}>
                          <PillIcon />
                        </div>
                        <div className="text-gray-400 text-sm">No medicines found</div>
                      </div>
                    )}
                  </div>
                </div>

                {/* Insight cards */}
                {insights.length > 0 && (
                  <div className="grid md:grid-cols-3 gap-4">
                    {insights.map(ins => (
                      <div key={ins.title} className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
                        <div className="w-10 h-10 rounded-xl flex items-center justify-center mb-3"
                          style={{ background: `${ins.color}18`, color: ins.color }}>
                          {ins.title.startsWith("#1") ? <TrophyIcon /> : ins.title.startsWith("Leading") ? <ChartIcon /> : <ScriptIcon />}
                        </div>
                        <h4 className="font-semibold text-gray-800 text-sm mb-1">{ins.title}</h4>
                        <p className="text-xs text-gray-500 leading-relaxed">{ins.desc}</p>
                      </div>
                    ))}
                  </div>
                )}
              </>
            )}
          </>
        )}
      </div>
  );
}